// @ts-check

const { base } = require('../../.lintstagedrc.shared');

// index.js and index.d.ts are generated by napi-rs. Exclude them from
// prettier and eslint so that builds don't undo formatting changes.
const GENERATED_FILES = ['index.js', 'index.d.ts'];

/** @param {string[]} files */
function excludeGenerated(files) {
  return files.filter(
    (f) => !GENERATED_FILES.some((g) => f.endsWith(`/${g}`) || f === g)
  );
}

module.exports = {
  '*.+(js|jsx|ts|tsx|css|graphql|json|less|md|mdx|sass|scss|yaml|yml)': (
    files
  ) => {
    const filtered = excludeGenerated(files);
    return filtered.length ? [`prettier --write ${filtered.join(' ')}`] : [];
  },
  '*.+(js|jsx|ts|tsx)': (files) => {
    const filtered = excludeGenerated(files);
    return filtered.length
      ? [`eslint --cache --quiet --fix ${filtered.join(' ')}`]
      : [];
  },
  'package.json': ['sort-package-json'],
  '*.rs': ['bash -c  "cargo clippy"'],
};
